function delay() {
    return new Promise((resolve) => {
        setTimeout(() => {
            resolve('resolved');
        }, 100);
    });
}

export async function getProcessedAsync() {
    const [valuesA, valuesC, valuesG, valuesT, peaksExitTimes, peaksNames, peaksQualities] =
        await Promise.all([
            getProcessedTValuesAsync(),
            getProcessedGValuesAsync(),
            getProcessedCValuesAsync(),
            getProcessedAValuesAsync(),
            getPeaksExitTimesAsync(),
            getPeaksNamesAsync(),
            getPeaksQualitiesAsync(),
        ]);

    const timeStepMs = 250;
    const info = "mock - ok";
    const parameters = [];

    return {
        valuesA, valuesC, valuesG, valuesT,
        peaksExitTimes, peaksNames, peaksQualities, timeStepMs,
        parameters,
        info
    };
}

export async function getProcessedAValuesAsync() {
    await delay();
    return getValuesA();
}

export async function getProcessedCValuesAsync() {
    await delay();
    return getValuesC();
}

export async function getProcessedGValuesAsync() {
    await delay();
    return getValuesG();
}

export async function getProcessedTValuesAsync() {
    await delay();
    return getValuesT();
}

export async function getPeaksQualitiesAsync() {
    await delay();
    return getPeaksQualities();
}

export async function getPeaksNamesAsync() {
    await delay();
    return getPeaksNames();
}

export async function getPeaksExitTimesAsync() {
    await delay();
    return getPeaksExitTimes();
}

const LOW_QUALITY_CHANCE = 0.1;
const LOW_QUALITY_MAX = 9;
const NORMAL_QUALITY_MIN = 10;
const NORMAL_QUALITY_MAX = 60;
const QUALITIES_SEED = 42;

// Seeded PRNG (mulberry32) so the mock "random" qualities are reproducible across loads —
// otherwise visual-snapshot e2e tests would see different bars on every run.
function mulberry32(seed) {
    let state = seed;
    return function () {
        state |= 0; state = (state + 0x6D2B79F5) | 0;
        let t = Math.imul(state ^ (state >>> 15), 1 | state);
        t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
        return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
    };
}

function getPeaksQualities() {
    const length = getPeaksNames().length;
    const peaksQualities = new Array(length);
    const random = mulberry32(QUALITIES_SEED);

    for (let i = 0; i < length; i++) {
        peaksQualities[i] = random() < LOW_QUALITY_CHANCE
            ? Math.floor(random() * (LOW_QUALITY_MAX + 1))
            : NORMAL_QUALITY_MIN + Math.floor(random() * (NORMAL_QUALITY_MAX - NORMAL_QUALITY_MIN + 1));
    }

    return peaksQualities;
}

